import{_ as a,c as i,o as e,a1 as o}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"Obsidian 整合: 自動儲存計畫 | plannotator","description":"學習 plannotator 的 Obsidian 整合設定方法。自動儲存批准的計畫到 vault，包含 frontmatter 和標籤產生功能，支援自訂儲存路徑。","frontmatter":{"title":"Obsidian 整合: 自動儲存計畫 | plannotator","sidebarTitle":"自動儲存到 Obsidian","subtitle":"Obsidian 整合: 自動儲存計畫 | plannotator","description":"學習 plannotator 的 Obsidian 整合設定方法。自動儲存批准的計畫到 vault，包含 frontmatter 和標籤產生功能，支援自訂儲存路徑。","tags":["plannotator","integration","obsidian","advanced"],"prerequisite":["start-getting-started"],"order":2},"headers":[],"relativePath":"zh-tw/backnotprop/plannotator/advanced/obsidian-integration/index.md","filePath":"zh-tw/backnotprop/plannotator/advanced/obsidian-integration/index.md"}'),n={name:"zh-tw/backnotprop/plannotator/advanced/obsidian-integration/index.md"};function r(l,t,s,d,c,h){return e(),i("div",null,[...t[0]||(t[0]=[o(`<h1 id="obsidian-整合-自動儲存計畫到筆記庫" tabindex="-1">Obsidian 整合：自動儲存計畫到筆記庫 <a class="header-anchor" href="#obsidian-整合-自動儲存計畫到筆記庫" aria-label="Permalink to &quot;Obsidian 整合：自動儲存計畫到筆記庫&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>自動將批准或拒絕的計畫儲存到 Obsidian vault</li><li>理解 frontmatter 和標籤的產生機制</li><li>自訂儲存路徑和資料夾</li><li>利用 backlink 建構知識圖譜</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><p>你在 Plannotator 中審查 AI 產生的計畫，批准後這些計畫就「消失」了。你希望把這些有價值的計畫儲存到 Obsidian，方便後續回顧和尋找，但手動複製貼上太麻煩，而且格式會亂。</p><h2 id="什麼時候用這一招" tabindex="-1">什麼時候用這一招 <a class="header-anchor" href="#什麼時候用這一招" aria-label="Permalink to &quot;什麼時候用這一招&quot;">​</a></h2><ul><li>你使用 Obsidian 作為知識管理工具</li><li>你希望長期儲存和回顧 AI 產生的實施計畫</li><li>你想利用 Obsidian 的 graph view 和標籤系統組織計畫</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>Plannotator 的 Obsidian 整合功能會在你批准或拒絕計畫時，自動將計畫內容儲存到你的 Obsidian vault。系統會：</p><ol><li><strong>偵測 vaults</strong>：自動從 Obsidian 設定檔讀取所有 vault</li><li><strong>產生 frontmatter</strong>：包含建立時間、來源和標籤</li><li><strong>擷取標籤</strong>：從計畫標題和程式碼區塊語言自動擷取標籤</li><li><strong>新增 backlink</strong>：插入 <code>[[Plannotator Plans]]</code> 連結，方便建構知識圖譜</li></ol><div class="info custom-block"><p class="custom-block-title">什麼是 Obsidian？</p><p>Obsidian 是一款本機優先的雙向連結筆記應用程式，支援 Markdown 格式，可透過圖視圖視覺化筆記之間的關係。</p></div><h2 id="🎒-開始前的準備" tabindex="-1">🎒 開始前的準備 <a class="header-anchor" href="#🎒-開始前的準備" aria-label="Permalink to &quot;🎒 開始前的準備&quot;">​</a></h2><p>確保已安裝並設定好 Obsidian。Plannotator 會自動偵測系統中的 vaults，但你至少需要有一個 vault 才能使用此功能。</p><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-開啟設定面板" tabindex="-1">第 1 步：開啟設定面板 <a class="header-anchor" href="#第-1-步-開啟設定面板" aria-label="Permalink to &quot;第 1 步：開啟設定面板&quot;">​</a></h3><p>在 Plannotator 介面中，點擊右上角的齒輪圖示開啟設定面板。</p><p>你應該看到設定對話框，包含多個設定選項。</p><h3 id="第-2-步-啟用-obsidian-整合" tabindex="-1">第 2 步：啟用 Obsidian 整合 <a class="header-anchor" href="#第-2-步-啟用-obsidian-整合" aria-label="Permalink to &quot;第 2 步：啟用 Obsidian 整合&quot;">​</a></h3><p>在設定面板中找到「Obsidian Integration」部分，點擊開關啟用該功能。</p><p>啟用後，Plannotator 會自動偵測系統中的 Obsidian vaults。</p><p>你應該看到下拉選單中列出偵測到的 vaults（例如 <code>My Vault</code>、<code>Work Notes</code>）。</p><h3 id="第-3-步-選擇-vault-和資料夾" tabindex="-1">第 3 步：選擇 vault 和資料夾 <a class="header-anchor" href="#第-3-步-選擇-vault-和資料夾" aria-label="Permalink to &quot;第 3 步：選擇 vault 和資料夾&quot;">​</a></h3><p>從下拉選單中選擇你希望儲存計畫的 vault。如果沒有偵測到 vault，可以：</p><ol><li>選擇「Custom path...」選項</li><li>在文字方塊中輸入 vault 的完整路徑</li></ol><p>然後在「Folder」欄位中設定儲存資料夾的名稱（預設為 <code>plannotator</code>）。</p><p>你應該看到下方的預覽路徑，顯示計畫將儲存的位置。</p><h3 id="第-4-步-批准或拒絕計畫" tabindex="-1">第 4 步：批准或拒絕計畫 <a class="header-anchor" href="#第-4-步-批准或拒絕計畫" aria-label="Permalink to &quot;第 4 步：批准或拒絕計畫&quot;">​</a></h3><p>設定完成後，正常審查 AI 產生的計畫。當你點擊「Approve」或「Send Feedback」時，計畫會自動儲存到設定的 vault 中。</p><p>你應該在 Obsidian 中看到新建立的檔案，檔案名稱格式為 <code>Title - Jan 2, 2026 2-30pm.md</code>。</p><h3 id="第-5-步-檢視儲存的檔案" tabindex="-1">第 5 步：檢視儲存的檔案 <a class="header-anchor" href="#第-5-步-檢視儲存的檔案" aria-label="Permalink to &quot;第 5 步：檢視儲存的檔案&quot;">​</a></h3><p>在 Obsidian 中開啟儲存的檔案，你會看到以下內容：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">created</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2026-01-24T14:30:00.000Z</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">source</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">plannotator</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tags</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">plan</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">authentication</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">typescript</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sql</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[[Plannotator Plans]]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Implementation Plan: User Authentication</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">...</span></span></code></pre></div><p>你應該注意到檔案頂部有 YAML frontmatter，包含建立時間、來源和標籤。</p><h2 id="檢查點-✅" tabindex="-1">檢查點 ✅ <a class="header-anchor" href="#檢查點-✅" aria-label="Permalink to &quot;檢查點 ✅&quot;">​</a></h2><ul><li>[ ] 設定面板中 Obsidian Integration 已啟用</li><li>[ ] 已選擇 vault（或輸入了自訂路徑）</li><li>[ ] 已設定資料夾名稱</li><li>[ ] 批准或拒絕計畫後，Obsidian 中出現新檔案</li><li>[ ] 檔案包含 frontmatter 和 <code>[[Plannotator Plans]]</code> backlink</li></ul><h2 id="frontmatter-和標籤詳解" tabindex="-1">Frontmatter 和標籤詳解 <a class="header-anchor" href="#frontmatter-和標籤詳解" aria-label="Permalink to &quot;Frontmatter 和標籤詳解&quot;">​</a></h2><h3 id="frontmatter-結構" tabindex="-1">Frontmatter 結構 <a class="header-anchor" href="#frontmatter-結構" aria-label="Permalink to &quot;Frontmatter 結構&quot;">​</a></h3><p>每個儲存的計畫都包含以下 frontmatter 欄位：</p><table tabindex="0"><thead><tr><th>欄位</th><th>值範例</th><th>說明</th></tr></thead><tbody><tr><td><code>created</code></td><td><code>2026-01-24T14:30:00.000Z</code></td><td>ISO 8601 格式的建立時間戳記</td></tr><tr><td><code>source</code></td><td><code>plannotator</code></td><td>固定值，標識來源</td></tr><tr><td><code>tags</code></td><td><code>[plan, authentication, typescript]</code></td><td>自動擷取的標籤陣列</td></tr></tbody></table><h3 id="標籤產生規則" tabindex="-1">標籤產生規則 <a class="header-anchor" href="#標籤產生規則" aria-label="Permalink to &quot;標籤產生規則&quot;">​</a></h3><p>Plannotator 使用以下規則自動擷取標籤：</p><ol><li><strong>預設標籤</strong>：總是包含 <code>plannotator</code> 標籤</li><li><strong>專案名稱標籤</strong>：從 git 儲存庫名稱或目錄名稱自動擷取</li><li><strong>標題關鍵字</strong>：從第一個 H1 標題中擷取有意義的詞（排除常見停用詞）</li><li><strong>程式碼語言標籤</strong>：從程式碼區塊的語言識別符擷取（例如 <code>typescript</code>、<code>sql</code>）。通用設定語言（如 <code>json</code>、<code>yaml</code>、<code>markdown</code>）會被自動過濾。</li></ol><p>停用詞清單（不會作為標籤）：</p><ul><li><code>the</code>, <code>and</code>, <code>for</code>, <code>with</code>, <code>this</code>, <code>that</code>, <code>from</code>, <code>into</code></li><li><code>plan</code>, <code>implementation</code>, <code>overview</code>, <code>phase</code>, <code>step</code>, <code>steps</code></li></ul><p>標籤數量限制：最多 7 個標籤，按擷取順序排列。</p><h3 id="檔案名稱格式" tabindex="-1">檔案名稱格式 <a class="header-anchor" href="#檔案名稱格式" aria-label="Permalink to &quot;檔案名稱格式&quot;">​</a></h3><p>檔案名稱採用可讀性強的格式：<code>Title - Jan 2, 2026 2-30pm.md</code></p><table tabindex="0"><thead><tr><th>部分</th><th>範例</th><th>說明</th></tr></thead><tbody><tr><td>標題</td><td><code>User Authentication</code></td><td>從 H1 擷取，限制 50 字元</td></tr><tr><td>日期</td><td><code>Jan 2, 2026</code></td><td>目前日期</td></tr><tr><td>時間</td><td><code>2-30pm</code></td><td>目前時間（12 小時制）</td></tr></tbody></table><h3 id="backlink-機制" tabindex="-1">Backlink 機制 <a class="header-anchor" href="#backlink-機制" aria-label="Permalink to &quot;Backlink 機制&quot;">​</a></h3><p>每個計畫檔案底部都會插入 <code>[[Plannotator Plans]]</code> 連結。這個 backlink 的作用：</p><ul><li><strong>知識圖譜連接</strong>：在 Obsidian 的 graph view 中，所有計畫都與同一個節點連接</li><li><strong>快速導覽</strong>：點擊 <code>[[Plannotator Plans]]</code> 可以建立一個索引頁面，彙總所有儲存的計畫</li><li><strong>雙向連結</strong>：在索引頁面中使用反向連結檢視所有計畫</li></ul><h2 id="跨平台支援" tabindex="-1">跨平台支援 <a class="header-anchor" href="#跨平台支援" aria-label="Permalink to &quot;跨平台支援&quot;">​</a></h2><p>Plannotator 自動偵測不同作業系統的 Obsidian 設定檔位置：</p><table tabindex="0"><thead><tr><th>作業系統</th><th>設定檔路徑</th></tr></thead><tbody><tr><td>macOS</td><td><code>~/Library/Application Support/obsidian/obsidian.json</code></td></tr><tr><td>Windows</td><td><code>%APPDATA%\\obsidian/obsidian.json</code></td></tr><tr><td>Linux</td><td><code>~/.config/obsidian/obsidian.json</code></td></tr></tbody></table><p>如果自動偵測失敗，可以手動輸入 vault 路徑。</p><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="問題-1-偵測不到-vaults" tabindex="-1">問題 1：偵測不到 vaults <a class="header-anchor" href="#問題-1-偵測不到-vaults" aria-label="Permalink to &quot;問題 1：偵測不到 vaults&quot;">​</a></h3><p><strong>症狀</strong>：下拉選單顯示「Detecting...」但沒有結果</p><p><strong>原因</strong>：Obsidian 設定檔不存在或格式錯誤</p><p><strong>解決方案</strong>：</p><ol><li>確認 Obsidian 已安裝並至少開啟過一次</li><li>檢查設定檔是否存在（參考上表路徑）</li><li>使用「Custom path...」手動輸入 vault 路徑</li></ol><h3 id="問題-2-儲存後找不到檔案" tabindex="-1">問題 2：儲存後找不到檔案 <a class="header-anchor" href="#問題-2-儲存後找不到檔案" aria-label="Permalink to &quot;問題 2：儲存後找不到檔案&quot;">​</a></h3><p><strong>症狀</strong>：批准計畫後，Obsidian 中沒有新檔案</p><p><strong>原因</strong>：vault 路徑錯誤或 Obsidian 未重新整理</p><p><strong>解決方案</strong>：</p><ol><li>檢查設定面板中的預覽路徑是否正確</li><li>在 Obsidian 中點擊「Reload vault」或按 <code>Cmd+R</code>（macOS）/ <code>Ctrl+R</code>（Windows/Linux）</li><li>檢查是否選擇了正確的 vault</li></ol><h3 id="問題-3-檔案名稱包含特殊字元" tabindex="-1">問題 3：檔案名稱包含特殊字元 <a class="header-anchor" href="#問題-3-檔案名稱包含特殊字元" aria-label="Permalink to &quot;問題 3：檔案名稱包含特殊字元&quot;">​</a></h3><p><strong>症狀</strong>：檔案名稱中出現 <code>_</code> 或其他取代字元</p><p><strong>原因</strong>：標題包含檔案系統不支援的字元（<code>&lt; &gt; : &quot; / \\ | ? *</code>）</p><p><strong>解決方案</strong>：這是預期行為，Plannotator 會自動取代這些字元��避免檔案系統錯誤。</p><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><p>Obsidian 整合功能讓你的計畫審查流程與知識管理無縫連接：</p><ul><li>✅ 自動儲存批准或拒絕的計畫</li><li>✅ 智慧擷取標籤，方便後續檢索</li><li>✅ 產生 frontmatter，統一中繼資料格式</li><li>✅ 新增 backlink，建構知識圖譜</li></ul><p>設定一次後，每次審查都會自動歸檔，不再需要手動複製貼上。</p><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../bear-integration/">Bear 整合</a></strong>。</p><p>你會學到：</p><ul><li>如何將計畫儲存到 Bear 筆記應用程式</li><li>Bear 整合與 Obsidian 整合的區別</li><li>使用 x-callback-url 自動建立筆記</li></ul></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開檢視原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>偵測 Obsidian vaults</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L135-L175" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>135-175</td></tr><tr><td>儲存計畫到 Obsidian</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L180-L227" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>180-227</td></tr><tr><td>擷取標籤</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L34-L74" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>34-74</td></tr><tr><td>產生 frontmatter</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L81-L89" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>81-89</td></tr><tr><td>產生檔案名稱</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L111-L127" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>111-127</td></tr><tr><td>Obsidian 設定儲存</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/obsidian.ts#L36-L43" target="_blank" rel="noreferrer"><code>packages/ui/utils/obsidian.ts</code></a></td><td>36-43</td></tr><tr><td>Settings UI 元件</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Settings.tsx#L387-L491" target="_blank" rel="noreferrer"><code>packages/ui/components/Settings.tsx</code></a></td><td>387-491</td></tr></tbody></table><p><strong>關鍵函式</strong>：</p><ul><li><code>detectObsidianVaults()</code>：讀取 Obsidian 設定檔，回傳可用的 vault 路徑清單</li><li><code>saveToObsidian(config)</code>：將計畫儲存到指定 vault，包含 frontmatter 和 backlink</li><li><code>extractTags(markdown)</code>：從計畫內容擷取標籤（標題關鍵字、程式碼語言、專案名稱）</li><li><code>generateFrontmatter(tags)</code>：產生 YAML frontmatter 字串</li><li><code>generateFilename(markdown)</code>：產生可讀的檔案名稱</li></ul><p><strong>業務規則</strong>：</p><ul><li>標籤數量最多 7 個（L73）</li><li>檔案名稱限制 50 字元（L102）</li><li>支援跨平台設定檔路徑偵測（L141-149）</li><li>自動建立不存在的資料夾（L208）</li></ul></details>`,79)])])}const k=a(n,[["render",r]]);export{b as __pageData,k as default};
